import type { SkillPackageType } from "@/types/skill";

/**
 * Lightweight descriptive metadata layered on top of the SkillConfig
 * generated by each preset. Used by the UI to render preset impact
 * summaries, focus labels, and "added / removed" highlights — does
 * not feed back into generation.
 */
export type PresetBundle = {
  id: string;
  focus: { en: string; ko: string };
  includedSkillTypes: SkillPackageType[];
  primaryKitStructure: SkillPackageType;
  /** File groups the preset emphasizes (Generated Files section labels). */
  expectedFileGroups: string[];
  /** Specific files the preset puts forward as the headline artifact. */
  emphasizedFiles: string[];
};

