export function getPresetBundle(presetId: string): PresetBundle | undefined {
  return PRESET_BUNDLES[presetId];
}

export type PresetDiff = {
  fromId: string;
  toId: string;
  addedTypes: SkillPackageType[];
  removedTypes: SkillPackageType[];
  primaryChanged: boolean;
  addedGroups: string[];
  removedGroups: string[];
};

export function diffPresets(fromId: string, toId: string): PresetDiff | null {
  const a = PRESET_BUNDLES[fromId];
  const b = PRESET_BUNDLES[toId];
  if (!a || !b) return null;
  const aSet = new Set(a.includedSkillTypes);
  const bSet = new Set(b.includedSkillTypes);
  const addedTypes = b.includedSkillTypes.filter((t) => !aSet.has(t));
  const removedTypes = a.includedSkillTypes.filter((t) => !bSet.has(t));
  const aGroups = new Set(a.expectedFileGroups);
  const bGroups = new Set(b.expectedFileGroups);
  const addedGroups = b.expectedFileGroups.filter((g) => !aGroups.has(g));
  const removedGroups = a.expectedFileGroups.filter((g) => !bGroups.has(g));
  return {
    fromId,
    toId,
    addedTypes,
    removedTypes,
    primaryChanged: a.primaryKitStructure !== b.primaryKitStructure,
    addedGroups,
    removedGroups,
  };
}
